import { useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AuthContext } from '../App';  // ← Import from App.js

function Navbar() {
  const { user, token, logout } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav className="bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 shadow-2xl sticky top-0 z-50">
      <div className="container mx-auto px-4">
        <div className="flex justify-between items-center h-20">
          
          <Link to="/" className="flex items-center space-x-3">
            <span className="text-2xl font-bold text-white">
              🎉 EventHub
            </span>
          </Link>

          <div className="hidden lg:flex items-center space-x-6">
            <Link to="/" className="text-white hover:bg-white hover:bg-opacity-20 px-4 py-2 rounded-lg transition">
              Home
            </Link>
            <Link to="/events" className="text-white hover:bg-white hover:bg-opacity-20 px-4 py-2 rounded-lg transition">
              Events
            </Link>

            {token ? (
              <>
                <Link to="/my-bookings" className="text-white hover:bg-white hover:bg-opacity-20 px-4 py-2 rounded-lg transition">
                  My Bookings
                </Link>

                <div className="flex items-center space-x-3 bg-white bg-opacity-20 px-4 py-2 rounded-full">
                  <span className="text-white font-semibold">
                    {user?.name}
                  </span>
                </div>

                <button
                  onClick={handleLogout}
                  className="bg-white text-red-600 px-6 py-2 rounded-full hover:shadow-xl transition font-semibold"
                >
                  Logout
                </button>
              </>
            ) : (
              <>
                <Link to="/login" className="text-white hover:bg-white hover:bg-opacity-20 px-6 py-2 rounded-full transition">
                  Login
                </Link>
                <Link to="/register" className="bg-white text-purple-600 px-6 py-2 rounded-full hover:shadow-xl transition font-semibold">
                  Sign Up Free
                </Link>
              </>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
